version: "3.9"

services:
  webui:
    build: .
    container_name: ebooks-webui
    ports:
      - "5002:5002"
    environment:
      # User / Group IDs (map to host for file permissions)
      UID: ${PUID}
      GID: ${PGID}
      TZ: ${TZ}

      # Downloader API (search + download)
      CWA_API_URL: "http://cwa-downloader:5000/request/api"
      CWA_USERNAME: "${CWA_USERNAME:-}"
      CWA_PASSWORD: "${CWA_PASSWORD:-}"

      # Admin auth for WebUI config API
      ADMIN_USER: "${ADMIN_USER:-admin}"
      ADMIN_PASS: "${ADMIN_PASS:-changeme}"

      # Database
      DATABASE_PATH: "/app/data/databases/goodreads.db"

      # Python runtime configs
      PYTHONUNBUFFERED: 1
      PYTHONPATH: /app

    volumes:
      - ./data:/app/data
      - ./config:/app/config
    depends_on:
      - cwa-downloader
    logging:
      driver: "json-file"
      options:
        max-size: "10m"
        max-file: "5"

  cwa-downloader:
    image: ghcr.io/calibrain/calibre-web-automated-book-downloader:latest
    container_name: cwa-downloader
    environment:
      # User / Group IDs
      UID: ${PUID}
      GID: ${PGID}
      TZ: ${TZ}

      # Flask app config (used internally by downloader)
      FLASK_HOST: 0.0.0.0
      FLASK_PORT: 5000

      # Optional external services
      FLARESOLVERR_URL: http://127.0.0.1:8191/v1

      # Logging and behavior
      LOG_LEVEL: DEBUG
      DRY_RUN: no
      WEBPAGE_CACHE_DAYS: 30

      # Calibre library path inside container
      CALIBRE_LIBRARY: /books

      # Python runtime
      PYTHONUNBUFFERED: 1
      PYTHONPATH: /app
    volumes:
      - ./books:/books
    ports:
      - "5000:5000"
    logging:
      driver: "json-file"
      options:
        max-size: "10m"
        max-file: "5"

  # Future service: Goodreads ↔️ Calibre-Web sync
  cwa-details:
    image: ghcr.io/crocodilestick/calibre-web-automated:latest
    container_name: cwa-details
    environment:
      UID: ${PUID}
      GID: ${PGID}
      TZ: ${TZ}
      PYTHONUNBUFFERED: 1
      PYTHONPATH: /app
    volumes:
      - ./books:/books
    ports:
      - "5001:5000"
    logging:
      driver: "json-file"
      options:
        max-size: "10m"
        max-file: "5"
    # Disabled by default until needed
    deploy:
      replicas: 0
